function refreshNowplaying(t,o,n){fetch(`https://ws.audioscrobbler.com/2.0/?method=user.getrecenttracks&user=${n}&limit=1&api_key=8593a81dd2f1069b64528adcd184e9b2&format=json`).then(function(n){return n.json()}).then(function(n){var n=n.recenttracks.track[0],e=!(!n["@attr"]||!n["@attr"].nowplaying);t.innerHTML=(e?"listening to ":"last listened to ")+n.name.toLowerCase(),o.classList.toggle("icon--spinning",e)}).catch(function(n){t.innerHTML="couldn't grab current song",o.classList.remove("icon--spinning")})}function setupNowplaying(n,e,t=3e4){let o=n.dataset.lastfmUsername;if(!o)throw"LastFM username not provided";var r=()=>refreshNowplaying(n,e,o);setInterval(r,t),r()}document.addEventListener("DOMContentLoaded",function(){var n=document.querySelector("#nowlistening");n&&setupNowplaying(n,document.querySelector("#nowlisteningicon"))});